    if len(unvisited_nodes) > 0:
        closest_node = unvisited_nodes[np.argmin(distance_matrix[current_node][unvisited_nodes])]

        if distance_matrix[current_node][closest_node] + distance_matrix[closest_node][depot_node] <= distance_matrix[current_node][max_demand_node] + distance_matrix[max_demand_node][depot_node]:
