import numpy as np

def select_next_node(current_node, truck_nodes, depot_node, unvisited_nodes, distance_matrix):
    shortest_distance = np.inf
    next_node = None

    for node in unvisited_nodes:
        if node not in truck_nodes:
            distance_to_node = distance_matrix[current_node][node]
            waiting_time = distance_matrix[depot_node][node]
            total_time = distance_to_node + waiting_time

            if total_time < shortest_distance:
                shortest_distance = total_time
                next_node = node

    return next_node
